    @GetMapping("/download/bulkupload/csv/{fileName}")
    @ResponseBody
    public ResponseEntity<Resource> downloadFileFromLocal(@PathVariable String fileName, HttpServletRequest req) throws IOException {
        Path path = null;
        Integer RESP_CODE = APIConstants.FAIL;
        if (!"".equals(fileName) && fileName != null) {
            if (fileName.equalsIgnoreCase("networkDetails")) {
                path = Paths.get("networkdetailscsvissue.csv");
            }
            if (fileName.equalsIgnoreCase("cases")) {
                path = Paths.get("casescsvissue.csv");
            }
            if (fileName.equalsIgnoreCase("ticketDetails")) {
                path = Paths.get("ticketdetailscsvissue.csv");
            }
            if (fileName.equalsIgnoreCase("macResetDetails")) {
                path = Paths.get("macResetdetailscsvissue.csv");
            }
        }
        Resource resource = null;
        Path pathTemp = null;
        try {
            resource = new UrlResource(path.toUri());
            pathTemp = resource.getFile().toPath();
        } catch (MalformedURLException e) {
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All download file  list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            e.printStackTrace();
        }
        log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All download file list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        RESP_CODE = APIConstants.SUCCESS;
        return ResponseEntity.ok().header(HttpHeaders.CONTENT_TYPE, Files.probeContentType(pathTemp)).header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + resource.getFilename() + "\"").body(resource);
    }

    @PostMapping("/login")
    public ResponseEntity<?> login(@Valid @RequestBody LoginPojo pojo, HttpServletRequest req) throws Exception {

        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            StaffUserService staffUserService = SpringContext.getBean(StaffUserService.class);
            List<StaffUser> dbStaffUserList = staffUserService.getStaffUserFromUsername(pojo.getUsername());
            if (dbStaffUserList == null || dbStaffUserList.size() <= 0) {
                //		ApplicationLogger.logger.info("Username or Password not matched");
                response.put(CommonConstants.RESPONSE_MESSAGE, "Username or Password not matched");
                RESP_CODE = APIConstants.FAIL;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Username or Password " + pojo.getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                StaffUser dbstaffuser = dbStaffUserList.get(0);
                ApplicationLogger.logger.info("Entered Password:" + pojo.getPassword() + ":In DB Password:" + dbstaffuser.getPassword());
                PasswordEncoder encoder = new BCryptPasswordEncoder();
                if (encoder.matches(pojo.getPassword(), dbstaffuser.getPassword())) {
                    //		ApplicationLogger.logger.info("Login Success");
                    LocalDateTime ldt = LocalDateTime.now();
                    dbstaffuser.setLast_login_time(ldt);
                    dbstaffuser.setFailcount(0);
                    staffUserService.save(dbstaffuser);
                    response.put(CommonConstants.RESPONSE_MESSAGE, "Login Success.");
                    RESP_CODE = APIConstants.SUCCESS;
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Username or Password " + pojo.getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                } else {
                    //		ApplicationLogger.logger.info("Password Not Match");
                    int intFailCount = dbstaffuser.getFailcount();
                    intFailCount++;
                    dbstaffuser.setFailcount(intFailCount);
                    staffUserService.save(dbstaffuser);
                    response.put(CommonConstants.RESPONSE_MESSAGE, "Password Not Match");
                    RESP_CODE = APIConstants.FAIL;
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "Password not match " + pojo.getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                }
            }
        } catch (CustomValidationException ce) {
            //	ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "Username or Password: " + pojo.getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //	ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "Username or Password: " + pojo.getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        }

        return apiResponse(RESP_CODE, response);
    }

