    //    @PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_TAX_ALL + "\",\"" + AclConstants.OPERATION_TAX_ADD
//            + "\")")
//    @PreAuthorize("validatePermission(\"" + MenuConstants.TAX_CREATE + "\")")
    @PostMapping("/taxes")
    public ResponseEntity<?> createTax(@Valid @RequestBody TaxPojo pojo, HttpServletRequest req) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Create");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        try {
            TaxService taxService = SpringContext.getBean(TaxService.class);
            taxService.validateRequest(pojo, CommonConstants.OPERATION_ADD);
            boolean flag = taxService.duplicateVerifyAtSave(pojo.getName(),pojo.getMvnoId());
            if (flag) {
                if (getBUIdsFromCurrentStaff() != null && getBUIdsFromCurrentStaff().size() > 1)
                    throw new CustomValidationException(APIConstants.FAIL, Constants.AVOID_SAVE_MULTIPLE_BU, null);
                pojo = taxService.save(pojo);
                taxService.sendCreateDataShared(pojo, CommonConstants.OPERATION_ADD);
                response.put("tax", pojo);
                response.put(APIConstants.MESSAGE, "Successfully Created");
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, MessageConstants.TAX_NAME_EXITS);
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_INFO + "Tax with same name already exist" + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                return apiResponse(RESP_CODE, response, null);

            }
            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_TAX, AclConstants.OPERATION_TAX_ADD, req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());
        } catch (CustomValidationException ce) {
            //	ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //	ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

