//            + "\")")
//    @PreAuthorize("validatePermission(\"" + MenuConstants.TAX_EDIT + "\")")
    @PutMapping("/taxes/{id}")
    public ResponseEntity<?> updateTax(@Valid @RequestBody TaxPojo pojo, @PathVariable Integer id, HttpServletRequest req) throws Exception {
//        String oldname = SpringContext.getBean(TaxService.class).get(id).getName();
        Integer RESP_CODE = APIConstants.FAIL;
        TraceContext traceContext = tracer.currentSpan().context();
        HashMap<String, Object> response = new HashMap<>();
        MDC.put("type", "Update");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());

        try {
//            Integer oldObj = null;
//            if (pojo.getId() != null) {
//                oldObj = pojo.getId();
//            }
            TaxService taxService = SpringContext.getBean(TaxService.class);
            pojo.setId(id);
            taxService.validateRequest(pojo, CommonConstants.OPERATION_UPDATE);
            taxService.getEntityForUpdateAndDelete(pojo.getId(),pojo.getMvnoId());
            boolean flag = taxService.duplicateVerifyAtEdit(pojo.getName(), pojo.getId(),pojo.getMvnoId());
            if (flag) {
                Tax tax = taxService.get(id,pojo.getMvnoId());

                String updatedValues = UtilsCommon.getUpdatedDiff(taxService.convertTaxModelToTaxPojo(tax), pojo);
                pojo = taxService.save(pojo);
                // log.info("Tax update details:" );

                taxService.sendCreateDataShared(pojo, CommonConstants.OPERATION_UPDATE);
                response.put("tax", pojo);
                response.put(APIConstants.MESSAGE, "Successfully Updated");
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + " , updated tax Details " + updatedValues + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, MessageConstants.TAX_NAME_EXITS);
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_UNAUTHORIZED + LogConstants.LOG_ERROR + "Access denined for update operation " + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                return apiResponse(RESP_CODE, response, null);
            }
            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_TAX, AclConstants.OPERATION_TAX_EDIT, req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());
        } catch (CustomValidationException ce) {
            //	ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.MESSAGE, ce.getMessage());
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //	ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }


