//            + "\")")
//    @PreAuthorize("validatePermission(\"" + MenuConstants.TAX_DELETE + "\")")
    @DeleteMapping("/taxes/{id}")
    public ResponseEntity<?> deleteTax(@PathVariable Integer id, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Delete");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        TaxPojo taxPojo = new TaxPojo();
        try {
            TaxService taxService = SpringContext.getBean(TaxService.class);
            Tax tax = taxService.getEntityForUpdateAndDelete(id,mvnoId);
            if (tax != null) {
                TaxPojo pojo = taxService.convertTaxModelToTaxPojo(tax);
                taxService.validateRequest(pojo, CommonConstants.OPERATION_DELETE);
                taxService.deleteTax(id);
                taxService.sendCreateDataShared(pojo, CommonConstants.OPERATION_DELETE);
                response.put(APIConstants.MESSAGE, "Successfully Deleted");
//                response.put(CommonConstants.RESPONSE_MESSAGE, messagesProperty.get("api.tax.deleted"));
                RESP_CODE = APIConstants.SUCCESS;
                response.put("responseCode", HttpStatus.OK.value());
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete Tax" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_TAX, AclConstants.OPERATION_TAX_DELETE, req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());
            } else {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.object.not.found"), null);
            }
        } catch (CustomValidationException ce) {
            //	ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.MESSAGE, ce.getMessage());
            response.put("responseCode", RESP_CODE);
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete tax" + LogConstants.LOG_BY_NAME + taxPojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            if (ex instanceof RuntimeException) {
                //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                RESP_CODE = HttpStatus.METHOD_NOT_ALLOWED.value();
                response.put("responseCode", RESP_CODE);
                response.put(APIConstants.ERROR_TAG, ex.getMessage());
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete tax" + LogConstants.LOG_BY_NAME + taxPojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                ex.printStackTrace();
                RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
                response.put("responseCode", RESP_CODE);
                response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete tax" + LogConstants.LOG_BY_NAME + taxPojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

