    //    @PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_PLAN_SERVICE_ALL + "\",\""
//            + AclConstants.OPERATION_PLAN_SERVICE_ADD + "\")")
//    @PreAuthorize("validatePermission(\"" + MenuConstants.SERVICE_CREATE + "\")")
    @PostMapping("/planservice")
    public ResponseEntity<?> createPlanService(@Valid @RequestBody PlanPojo pojo, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Create");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());

        try {
            PlanServiceService planserviceService = SpringContext.getBean(PlanServiceService.class);
            planserviceService.validateRequest(pojo, CommonConstants.OPERATION_ADD);
            boolean flag = planserviceService.duplicateVerifyAtSave(pojo.getName(),mvnoId);
            boolean flag1 = planserviceService.duplicateVerifyAtSaveICCode(pojo.getIccode(),mvnoId);
            boolean flag2 = planserviceService.duplicateVerifyAtSaveICName(pojo.getIcname(),mvnoId);
            if (flag && flag2 && flag1) {
                if (getBUIdsFromCurrentStaff() != null && getBUIdsFromCurrentStaff().size() > 1)
                    throw new CustomValidationException(APIConstants.FAIL, Constants.AVOID_SAVE_MULTIPLE_BU, null);
                PlanPojo planServicePojo = planserviceService.save(pojo,mvnoId);
                planServicePojo.setPcategoryId(pojo.getPcategoryId());
                planserviceService.sendCreatedDataShared(planServicePojo, CommonConstants.OPERATION_ADD);
                response.put("plan", planServicePojo);
                response.put(APIConstants.MESSAGE, "Successfully Created");
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan Service" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();

                if (!flag) {
                    response.put(APIConstants.ERROR_TAG, MessageConstants.SERVICE_NAME_EXITS);
                }
                if (!flag1) {
                    response.put(APIConstants.ERROR_TAG, MessageConstants.ICCODE_EXISTS);
                }
                if (!flag2) {
                    response.put(APIConstants.ERROR_TAG, MessageConstants.ICNAME_EXISTS);
                }
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan Service" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_INFO + "Investment code with same name already exist" + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                //response.put(APIConstants.ERROR_TAG, MessageConstants.SERVICE_NAME_EXITS);
                return apiResponse(RESP_CODE, response, null);
            }
//            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_PLAN_SERVICE, AclConstants.OPERATION_PLAN_SERVICE_ADD,
//                    req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan Service" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan Service" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

