//    @PreAuthorize("validatePermission(\"" + MenuConstants.CHARGE + "\")")
    @PostMapping("/charge/list")
    public ResponseEntity<?> getChargeList(@RequestBody PaginationRequestDTO requestDTO, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId
    ) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        HashMap<String, Object> response = new HashMap<>();
        Page<Charge> chargeList = null;

        try {
            ChargeService chargeService = SpringContext.getBean(ChargeService.class);
            TaxService taxService = SpringContext.getBean(TaxService.class);
            requestDTO = setDefaultPaginationValues(requestDTO);
            chargeList = chargeService.getList(requestDTO.getPage(), requestDTO.getPageSize(), requestDTO.getSortBy(), requestDTO.getSortOrder(), requestDTO.getFilters(),mvnoId);

            if (null != chargeList && 0 < chargeList.getSize()) {
                response.put("chargelist", chargeList.getContent().stream().peek(charge -> {
                    if (charge != null) {
                        Double taxAmount = taxService.getTaxAmountFromCharge(charge, null);
                        DecimalFormat df = new DecimalFormat("0.00");
                        taxAmount = Double.parseDouble(df.format(taxAmount));
                        charge.setTaxamount(taxAmount);

                    }
                }).map(data -> chargeMapper.domainToDTO(data, new CycleAvoidingMappingContext())).collect(Collectors.toList()));

            } else {
                response.put("chargelist", new ArrayList<>());
            }
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All charge list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All charge list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All charge list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, chargeList);
    }

