    //    @PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_CHARGE_ALL + "\",\""
//            + AclConstants.OPERATION_CHARGE_VIEW + "\")")
//@PreAuthorize("validatePermission(\"" + MenuConstants.CHARGE + "\")")
    @GetMapping("/charge/{id}")
    public ResponseEntity<?> getChargeById(@PathVariable Integer id, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        HashMap<String, Object> response = new HashMap<>();
        try {
            ChargeService chargeService = SpringContext.getBean(ChargeService.class);
            if (id == null) {
                RESP_CODE = APIConstants.NOT_FOUND;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch charge by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                Charge charge = chargeService.get(id,mvnoId);
                TaxService taxService = SpringContext.getBean(TaxService.class);
                Double taxAmount = taxService.getTaxAmountFromCharge(charge, null);
                ChargePojo pojo = chargeService.convertChargeModelToChargePojo(charge);
                pojo.setTaxamount(taxAmount);

                if (charge == null) {
                    RESP_CODE = APIConstants.NOT_FOUND;
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch charge by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                } else {
                    response.put("chargebyid", pojo);
                    RESP_CODE = APIConstants.SUCCESS;
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch charge by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                    auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CHARGE, AclConstants.OPERATION_CHARGE_VIEW, req.getRemoteAddr(), null, charge.getId().longValue(), charge.getName());
                }
            }
        } catch (CustomValidationException e) {
            //		ApplicationLogger.logger.error(MODULE + e.getStackTrace(), e);
            e.printStackTrace();
            RESP_CODE = e.getErrCode();
            response.put(APIConstants.ERROR_TAG, e.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch charge by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch charge by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

