    //    @PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_POSTPAID_PLAN_ALL + "\",\""
//            + AclConstants.OPERATION_POSTPAID_PLAN_VIEW + "\")")
//@PreAuthorize("validatePermission(\"" + MenuConstants.PLAN+ "\")")
    @GetMapping("/postpaidplan/{id}")
    public ResponseEntity<?> getPlanById(@PathVariable Integer id, HttpServletRequest req,@RequestParam ("mvnoId") Integer mvnoId) throws Exception {

        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE;
        HashMap<String, Object> response = new HashMap<>();
        try {
            PostpaidPlanService postpaidPlanService = SpringContext.getBean(PostpaidPlanService.class);
            PostpaidPlan postpaidPlan = postpaidPlanService.getPostpaidPlanForEdit(id,mvnoId);

            TaxDetailCountReqDTO taxDetailCountReqDTO = new TaxDetailCountReqDTO();
            taxDetailCountReqDTO.setPlanId(id);
//            ClientService clientService = clientServiceSrv.getByName(ChargeConstants.CLIENT_SERVICE_LOCATION_ID);
//            if (clientService != null) {
//                taxDetailCountReqDTO.setLocationId(Integer.parseInt(clientService.getValue()));
//            }
            postpaidPlan.setTaxamount(taxService.taxCalculationByPlan(taxDetailCountReqDTO, postpaidPlan.getChargeList()));
            //obj.setTaxamount(taxService.taxCalculationByPlan(taxDetailCountReqDTO));

            List<Productplanmapping> productplanmappingList = productplanmappingService.getProductPlanMappingByPlanId(postpaidPlan.getId());
            postpaidPlan.setProductplanmappingList(productplanmappingList.stream().map(productplanmapping -> productplanmappingmapper.domainToDTO(productplanmapping, new CycleAvoidingMappingContext())).collect(Collectors.toList()));
            List<PlanQosMappingEntity> planQosMappingEntities = planQosMappingService.getPlanQosMappingByPlanId(Long.valueOf(id));
            if (planQosMappingEntities.size() > 0) {
                postpaidPlan.setPlanQosMappingEntities(planQosMappingEntities);
            }
            List<PlanQosMappingPojo> planQosMappingPojoList = new LinkedList<>();
            for (PlanQosMappingEntity planQosMappingEntity : planQosMappingEntities) {
                PlanQosMappingPojo planQosMappingPojo = planQosMappingMapper.domainToDTO(planQosMappingEntity, new CycleAvoidingMappingContext());
                planQosMappingPojoList.add(planQosMappingPojo);
            }
            postpaidPlan.setPlanQosMappingEntityList(planQosMappingPojoList);
            if (postpaidPlan.getServiceId() != null) {
                postpaidPlan.setServiceName(serviceRepository.findServiceNameById(postpaidPlan.getServiceId()));
            }
            if (postpaidPlan.getTimebasepolicyId() != null) {
                postpaidPlan.setTimebasepolicyName(timeBasePolicyService.getEntityById(postpaidPlan.getTimebasepolicyId().longValue(),postpaidPlan.getMvnoId()).getName());
            }
            List<DiscountMappingPojo> discountList = discountService.getDiscountMappingsByPlanId(id);
            if (discountList != null && !discountList.isEmpty()) {
                postpaidPlan.setDiscountList(discountList);
            }
            response.put("postPaidPlan", postpaidPlanMapper.domainToDTO(postpaidPlan, new CycleAvoidingMappingContext()));
            if (postpaidPlan.getEndDate().isBefore(LocalDate.now())) {
                postpaidPlan.setStatus("Expired");
            }
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All postpaidplan list by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_POSTPAID_PLAN, AclConstants.OPERATION_POSTPAID_PLAN_VIEW, req.getRemoteAddr(), null, postpaidPlan.getId().longValue(), postpaidPlan.getDisplayName());
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All postpaid plan list by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (EntityNotFoundException enfe) {
            //		ApplicationLogger.logger.error(MODULE + enfe.getStackTrace(), enfe);
            enfe.printStackTrace();
            RESP_CODE = 404;
            response.put(APIConstants.ERROR_TAG, "Not Found!");
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All postpaid plan list by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + enfe.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All postpaid plan list by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

