//    @PreAuthorize("validatePermission(\"" + MenuConstants.PLAN_CREATE + "\")")
    @PostMapping("/postpaidplan")
    public ResponseEntity<?> createPostpaidPlan(@Valid @RequestBody PostpaidPlanPojo pojo, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Create");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            PostpaidPlanService postpaidPlanService = SpringContext.getBean(PostpaidPlanService.class);
            postpaidPlanService.validateRequest(pojo, CommonConstants.OPERATION_ADD);
            boolean flag = postpaidPlanService.duplicateVerifyAtSave(pojo.getName(),pojo.getMvnoId());
            boolean isSameStaff = postpaidPlanService.isSameStaff(pojo.getName(),pojo.getMvnoId());
//            Productplanmapping productplanmapping = new Productplanmapping();
            if (flag) {
                if (getBUIdsFromCurrentStaff() != null && getBUIdsFromCurrentStaff().size() > 1)
                    throw new CustomValidationException(APIConstants.FAIL, Constants.AVOID_SAVE_MULTIPLE_BU, null);

//                    productplanmapping.setProductCategoryId(pojo.getProduct_category());
//                    productplanmapping.setProduct_type(pojo.getProduct_type());


                pojo = postpaidPlanService.save(pojo);
                postpaidPlanService.sendCreateDataShared(pojo, CommonConstants.OPERATION_ADD, false);
                //		workflowAuditService.workFlowAuditPlan(pojo, getLoggedInUserId());
                response.put("postpaidplan", pojo);

//                    Long aLong = Long.valueOf(pojo.getId());
//                    productplanmapping.setPlan_id(aLong);
//                    planMappingRepository.save(productplanmapping);

                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                String errMsg;
                if (!isSameStaff) {
                    errMsg = MessageConstants.POSTPAID_PLAN_NAME_EXITS_DIFF_STAFF;
                } else {
                    errMsg = MessageConstants.POSTPAID_PLAN_NAME_EXITS;
                }
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, errMsg);
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_INFO + "plan with same name already exist" + LogConstants.LOG_STATUS_CODE + RESP_CODE);

                return apiResponse(RESP_CODE, response, null);
            }
            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_POSTPAID_PLAN, AclConstants.OPERATION_POSTPAID_PLAN_ADD, req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

