    public ResponseEntity<?> updatePostpaidPlan(@RequestBody PostpaidPlanPojo pojo, @PathVariable Integer id, HttpServletRequest req,@RequestParam ("mvnoId") Integer mvnoId) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Update");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        String oldname = SpringContext.getBean(PostpaidPlanService.class).get(id,mvnoId).getName();
        try {
            PostpaidPlanService postpaidPlanService = SpringContext.getBean(PostpaidPlanService.class);
            pojo.setId(id);
            PostpaidPlan plan = postpaidPlanService.getEntityForUpdateAndDelete(id,mvnoId);
            Double oldOfferPrice = plan.getOfferprice();
            Double oldTaxAmount = plan.getChargeList().stream().filter(charge -> charge.getCharge() != null).filter(charge -> charge.getCharge().getTaxamount() != null).mapToDouble(charge -> charge.getCharge().getTaxamount()).sum();
            Double newOfferPrice = pojo.getOfferprice();
            Double newTaxAmount = pojo.getChargeList().stream().filter(charge -> charge.getCharge() != null).filter(charge -> charge.getCharge().getTaxamount() != null).mapToDouble(charge -> charge.getCharge().getTaxamount()).sum();
            postpaidPlanService.validateRequest(pojo, CommonConstants.OPERATION_UPDATE);
            boolean flag = postpaidPlanService.duplicateVerifyAtEdit(pojo.getName(), pojo.getId(),mvnoId);
            String updatedValues = UtilsCommon.getUpdatedDiff(postpaidPlanService.convertPostpaidPlanModelToPostpaidPlanPojo(plan), pojo);
            boolean isSameStaff = postpaidPlanService.isSameStaff(pojo.getName(),pojo.getMvnoId());
            if (flag) {
                postpaidPlanService.checkServiceAreaWhileDeletingPlan(plan, pojo);
                postpaidPlanService.checkCustomerPlanChargeChange(plan,pojo);
                pojo.setMvnoId(mvnoId);
                pojo = postpaidPlanService.save(pojo);
                    UpdatePlanPricesMessage updatePlanPricesMessage = new UpdatePlanPricesMessage(plan.getId().longValue(), newOfferPrice, newTaxAmount);
                    kafkaMessageSender.send(new KafkaMessageData(updatePlanPricesMessage, UpdatePlanPricesMessage.class.getSimpleName()));
//                    messageSender.send(updatePlanPricesMessage, RabbitMqConstants.UPDATE_PLAN_PRICES_IN_CRM)
                postpaidPlanService.sendCreateDataShared(pojo, CommonConstants.OPERATION_UPDATE, false);
                response.put("postpaidplan", pojo);
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update PostPaid Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + " , updated postpaid plan Details " + updatedValues + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                String errMsg;
                if (!isSameStaff) {
                    errMsg = MessageConstants.POSTPAID_PLAN_NAME_EXITS_DIFF_STAFF;
                } else {
                    errMsg = MessageConstants.POSTPAID_PLAN_NAME_EXITS;
                }
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, errMsg);
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update PostPaid Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_UNAUTHORIZED + LogConstants.LOG_ERROR + "Access denined for update operation" + LogConstants.LOG_STATUS_CODE + RESP_CODE);

                return apiResponse(RESP_CODE, response, null);
            }
            auditLogService.addAuditEntry(AclConstants.ACL_CLASS_POSTPAID_PLAN, AclConstants.OPERATION_POSTPAID_PLAN_EDIT, req.getRemoteAddr(), updatedValues, pojo.getId().longValue(), pojo.getName());

        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.MESSAGE, ce.getMessage());
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update PostPaid Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);

        } catch (Exception ex) {
            ///		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update PostPaid Plan" + LogConstants.LOG_BY_NAME + pojo.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);

        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

