    @DeleteMapping("/postpaidplan/{id}")
    public ResponseEntity<?> deletePostpaidPlan(@PathVariable Integer id, HttpServletRequest req,@RequestParam ("mvnoId") Integer mvnoId) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        MDC.put("type", "Delete");
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Delete");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        HashMap<String, Object> response = new HashMap<>();
        try {
            PostpaidPlanService postpaidPlanService = SpringContext.getBean(PostpaidPlanService.class);
            PostpaidPlan plan = postpaidPlanService.getEntityForUpdateAndDelete(id,mvnoId);
            if (plan != null) {
                PostpaidPlanPojo pojo = postpaidPlanService.convertPostpaidPlanModelToPostpaidPlanPojo(plan);
                postpaidPlanService.validateRequest(pojo, CommonConstants.OPERATION_DELETE);
                postpaidPlanService.deletePostpaidPlan(id,mvnoId);
                postpaidPlanService.sendCreateDataShared(pojo, CommonConstants.OPERATION_DELETE, false);
                response.put(CommonConstants.RESPONSE_MESSAGE, messagesProperty.get("api.postpaid.plan.deleted"));
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete PostPaid Plan" + LogConstants.LOG_BY_NAME + postpaidPlanService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                //logger.info(MODULE+"country with id"+id+" is Successfully deleted");
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_POSTPAID_PLAN, AclConstants.OPERATION_POSTPAID_PLAN_DELETE, req.getRemoteAddr(), null, pojo.getId().longValue(), pojo.getName());

            } else {
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.object.not.found"), null);
            }
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete PostPaid Plan" + LogConstants.LOG_BY_NAME + postpaidPlanService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);


        } catch (Exception ex) {
            if (ex instanceof RuntimeException) {
                ///			ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                RESP_CODE = HttpStatus.METHOD_NOT_ALLOWED.value();
                response.put(APIConstants.ERROR_TAG, ex.getMessage());
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete PostPaid Plan" + LogConstants.LOG_BY_NAME + postpaidPlanService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);

            } else {
                //			ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                ex.printStackTrace();
                RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
                response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete PostPaid Plan" + LogConstants.LOG_BY_NAME + postpaidPlanService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);

            }
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

