    @ApiOperation(value = "Get list of CustomerNotes by customerId in the system")
    @GetMapping("/findAllCustomerNotesWithPagination/{id}")
    public ResponseEntity<Map<String, Object>> findAllCustomerNotesWithPagination(
            @PathVariable Long id,
            @RequestParam(value = "page", defaultValue = "1", required = false) Integer page,
            @RequestParam(value = "pageSize", defaultValue = "5", required = false) Integer pageSize,
            HttpServletRequest request) {

        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();

        // Set MDC (Mapped Diagnostic Context) for logging
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, request.getHeader(LogConstants.TRACE_ID)); // Fixed traceId assignment
        MDC.put("spanId", traceContext.spanIdString());

        Integer responseCode = APIConstants.FAIL;

        try {
            // Pagination settings
            PaginationRequestDTO paginationRequestDTO = new PaginationRequestDTO();
            paginationRequestDTO.setPage(page);
            paginationRequestDTO.setPageSize(pageSize);
            paginationRequestDTO = setDefaultPaginationValues(paginationRequestDTO);

            // Fetch paginated results
            Page<CustomerNotesDto> customerNotesList = customersService.findAllCustomerNoteWithPagination(paginationRequestDTO, id);

            if (customerNotesList == null || customerNotesList.isEmpty()) {
                response.put("customerNotesList", Collections.emptyList());
                response.put("message", "No Records Found!");
                log.debug(LogConstants.REQUEST_FROM + request.getHeader("requestFrom") +
                        LogConstants.REQUEST_FOR + "Get list of CustomerNotes by customerId: " + id +
                        LogConstants.REQUEST_BY + getLoggedInUser().getUsername() +
                        LogConstants.LOG_STATUS + LogConstants.LOG_NO_RECORD_FOUND +
                        LogConstants.LOG_STATUS_CODE + APIConstants.SUCCESS);
            } else {
                log.info(LogConstants.REQUEST_FROM + request.getHeader("requestFrom") +
                        LogConstants.REQUEST_FOR + "Get list of CustomerNotes by customerId: " + id +
                        LogConstants.REQUEST_BY + getLoggedInUser().getUsername() +
                        LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS +
                        LogConstants.LOG_STATUS_CODE + APIConstants.SUCCESS);

                response.put("customerNotesList", customerNotesList);
            }
            responseCode = APIConstants.SUCCESS;

        } catch (CustomValidationException e) {
            responseCode = e.getErrCode();
            response.put(APIConstants.ERROR_MESSAGE, e.getMessage());

            log.error(LogConstants.REQUEST_FROM + request.getHeader("requestFrom") +
                    LogConstants.REQUEST_FOR + "Get list of CustomerNotes by customerId: " + id +
                    LogConstants.REQUEST_BY + getLoggedInUser().getUsername() +
                    LogConstants.LOG_STATUS + LogConstants.LOG_FAILED +
                    LogConstants.LOG_ERROR + e.getMessage() +
                    LogConstants.LOG_STATUS_CODE + responseCode);

        } catch (Exception e) {
            log.error(LogConstants.REQUEST_FROM + request.getHeader("requestFrom") +
                    LogConstants.REQUEST_FOR + "Get list of CustomerNotes by customerId: " + id +
                    LogConstants.REQUEST_BY + getLoggedInUser().getUsername() +
                    LogConstants.LOG_STATUS + LogConstants.LOG_FAILED +
                    LogConstants.LOG_ERROR + e.getMessage() +
                    LogConstants.LOG_STATUS_CODE + APIConstants.FAIL);

            response.put(APIConstants.ERROR_MESSAGE, e.getMessage());

        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove(LogConstants.TRACE_ID);
            MDC.remove("spanId");
        }

        return (ResponseEntity<Map<String, Object>>) apiResponse(responseCode,  response);
    }

//    @PreAuthorize("validatePermission(\"" + MenuConstants.PrepaidCustomers.PREPAID_CUSTOMERS_LIST + "\",\"" + MenuConstants.PostpaidCustomers.POSTPAID_CUSTOMERS_LIST + "\",\"" + MenuConstants.PrepaidCustomerCAF.PREPAID_CAF_CUSTOMERS + "\",\"" + MenuConstants.PostpaidCustomerCAF.POSTPAID_CAF_CUSTOMERS + "\" )")
    @PostMapping("/customers/search/{type}")
    public ResponseEntity<?> searchCustomer(@RequestBody PaginationRequestDTO requestDTO, HttpServletRequest req,
                                            @PathVariable String type,
                                            @RequestParam("mvnoId") Integer mvnoId) {
        Integer RESP_CODE = APIConstants.FAIL;
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Search");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        HashMap<String, Object> response = new HashMap<>();
        Page<CustomerListPojo> customersList = null;
        try {
            requestDTO = setDefaultPaginationValues(requestDTO);
            ValidationData validationData = validateSearchCriteria(requestDTO.getFilters());
            if (validationData.isValid()) {
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, validationData.getMessage());
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + validationData.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                return apiResponse(RESP_CODE, response);

            }
            CustomersService subscriberService = SpringContext.getBean(CustomersService.class);
            if (type.equalsIgnoreCase("Both")) {
                type = null;
            }
            customersList = subscriberService.searchCustomersByCustomerType(requestDTO.getFilters(), requestDTO.getPage(), requestDTO.getPageSize(), requestDTO.getSortBy(), requestDTO.getSortOrder(), type, requestDTO.getStatus(), requestDTO.getFromDate(), requestDTO.getToDate(),mvnoId);
            Integer Response = 0;
            if (customersList.isEmpty()) {
                Response = APIConstants.NO_CONTENT_FOUND;
                response.put(APIConstants.MESSAGE, "No Records Found!");
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                return apiResponse(Response, response);

            }
            if (null != customersList && 0 < customersList.getSize()) {
                response.put("customerList", customersList.getContent());
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, null, null, null, "");
            } else {
                response.put("customerList", new ArrayList<>());
            }
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (RuntimeException re) {
            re.printStackTrace();
            RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
            response.put(APIConstants.ERROR_TAG, re.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + re.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception e) {
            e.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, e.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search customers using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, customersList);
    }

