    @GetMapping("/customers/{id}")
    public ResponseEntity<?> getCustomersById(@PathVariable Integer id, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            CustomersService customersService = SpringContext.getBean(CustomersService.class);
            PostpaidPlanService planService = SpringContext.getBean(PostpaidPlanService.class);

            Customers customers = customersRepository.findById(id).get();
            if (customers == null) {
                RESP_CODE = APIConstants.NOT_FOUND;
                response.put("message", "Customer is not found by given id : " + id);
//                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, req.getRemoteAddr(), null, id.longValue(), "");
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                CustomersPojo pojo = customerMapper.domainToDTO(customers, new CycleAvoidingMappingContext());
                if (pojo != null) {
                    // TODO: pass mvnoID manually 6/5/2025
                    List<ChildCustomer> optionalChildCustomer = childCustomerRepo.findBasicInfo(customers.getId().longValue(), Arrays.asList(customers.getMvnoId().longValue(),1L));
                    if(!optionalChildCustomer.isEmpty()){
                        ChildCustomer childCustomer = optionalChildCustomer.get(0);
                        pojo.setLoginUsername(childCustomer.getUserName());
                        pojo.setLoginPassword(childCustomer.getPassword());
                    }
                    DecimalFormat df = new DecimalFormat("0.0000000");

                    if (pojo.getLatitude() != null && !pojo.getLatitude().isEmpty() && isNumeric(pojo.getLatitude()))
                        pojo.setLatitude(df.format(Double.parseDouble(pojo.getLatitude())));

                    if (pojo.getLongitude() != null && !pojo.getLongitude().isEmpty() && isNumeric(pojo.getLongitude()))
                        pojo.setLongitude(df.format(Double.parseDouble(pojo.getLongitude())));
                }
                if(pojo.getUsername().equalsIgnoreCase(pojo.getAcctno())){
                    pojo.setIsCredentialMatchWithAccountNo(true);
                }
                CustQuotaService custQuotaService = SpringContext.getBean(CustQuotaService.class);
                String parentCustQuta = custQuotaService.getParentQuotaType(pojo.getId());
                pojo.setParentQuotaType(parentCustQuta);
                List<CustMacMappping> custMacAddressList = custMacMapppingRepository.findByCustomerId(customers.getId());
                List<String> macAddressList = custMacAddressList.stream().map(CustMacMappping::getMacAddress).collect(Collectors.toList());
                pojo.setMACADDRESS(String.join(",", macAddressList));
                String branchName = "";
                List<RegionBranchMapping> regionBranchList = new ArrayList<>();
                if (customers.getBranch() != null) {
                    branchName = branchRepository.findNameById(customers.getBranch());
                    regionBranchList = regionBranchRepository.findAllBybranchId(customers.getBranch());
                } else {
                    branchName = partnerRepository.findBranchNameByPartnerId(customers.getPartner().getId());
                }
                pojo.setBranchName(branchName);
                if (regionBranchList != null && regionBranchList.size() > 0) {
                    List<Region> regions = regionBranchList.stream().map(RegionBranchMapping::getRegionid).collect(Collectors.toList());
                    List<String> regionNames = regions.stream().map(Region::getRname).collect(Collectors.toList());
                    List<BusinessVerticalsMapping> businessVerticals = businessVerticalsMappingRepository.findByRegionId(regions.get(0).getId());
                    if (businessVerticals != null) {

                        Set<String> buVnames = businessVerticals.stream().map(x -> x.getBusinessVerticals().getVname()).collect(Collectors.toSet());

                        pojo.setBuVerticals(String.join(",", buVnames));
                    }
                    pojo.setRegionName(String.join(",", regionNames));
                }
                if (customers.getParentCustomers() != null) {
                    pojo.setInvoiceType(customers.getInvoiceType());
                    pojo.setParentCustomerId(customers.getParentCustomers().getId());
                    pojo.setParentCustomerName(customers.getParentCustomers().getFullName());
//                    if (customers.getInvoiceType().equals(CommonConstants.INVOICE_TYPE_GROUP))
                    if (customers.getParentCustomers().getBillday() != null) {
                        pojo.setBillday(customers.getParentCustomers().getBillday());
                    }
                }
                if (pojo != null) {
                    if (pojo.getOltid() != null) {
                        pojo.setOltName(networkDeviceRepository.findDeviceNameById(pojo.getOltid()));
                    }
                    if (pojo.getMasterdbid() != null) {
                        pojo.setMasterdbName(networkDeviceRepository.findDeviceNameById(pojo.getMasterdbid()));
                    }
                    if (pojo.getSplitterid() != null) {
                        pojo.setSplitterName(networkDeviceRepository.findDeviceNameById(pojo.getSplitterid()));
                    }
                }
                Integer cprId;
                if (pojo != null && pojo.getPlanMappingList() != null && pojo.getPlanMappingList().size() > 0) {
                    for (CustPlanMapppingPojo custPlanMappping : pojo.getPlanMappingList()) {
                        if (custPlanMappping.getLinkAcceptanceDTO() == null) {
                            CustPlanMapppingPojo linkAcceptanceDATA = customersService.getLinkAcceptanceDTOByCustId(id, custPlanMappping.getPlanId());
                            custPlanMappping.setLinkAcceptanceDTO(linkAcceptanceDATA.getLinkAcceptanceDTO());
                        }

                        Double discount = custPlanMappping.getDiscount();
                        if (discount != null) {
                            DecimalFormat df = new DecimalFormat("0.00");
                            custPlanMappping.setDiscount(Double.parseDouble(df.format(discount)));
                        }


                        if (custPlanMappping.getPlanId() != null) {
                            PostpaidPlan postpaidPlan = planService.get(custPlanMappping.getPlanId(),customers.getMvnoId().intValue());
                            if (postpaidPlan != null) {
                                if (postpaidPlan.getValidity() != null)
                                    custPlanMappping.setValidity(postpaidPlan.getValidity());
                                if (postpaidPlan.getUnitsOfValidity() != null) {
                                    custPlanMappping.setUnitsOfValidity(postpaidPlan.getUnitsOfValidity());
                                }
                                if (postpaidPlan.getName() != null)
                                    custPlanMappping.setPlanName(postpaidPlan.getName());
                                custPlanMappping.setPlangroup(postpaidPlan.getPlanGroup());
                                custPlanMappping.setServiceId(postpaidPlan.getServiceId());

                            }
                        }
                    }
                }
                //Add appliend discount
                CustPlanMappingService mappingService = SpringContext.getBean(CustPlanMappingService.class);
                Double discount = mappingService.getCustomerDiscount(id, null);
                if (discount != null) {
                    DecimalFormat df = new DecimalFormat("0.00");
                    pojo.setDiscount(Double.parseDouble(df.format(discount)));
                } else pojo.setDiscount(discount);
                List<CustMacMapppingPojo> custMacMapppingList = pojo.getCustMacMapppingList().stream().filter(custMacMapppingPojo -> !custMacMapppingPojo.getIsDeleted()).collect(Collectors.toList());
                pojo.setCustMacMapppingList(custMacMapppingList);


                String customerTypeName = customersService.getCustomerType(customers.getCusttype());
                if (!pojo.getUsername().equalsIgnoreCase(customerTypeName) || pojo.getUsername().equalsIgnoreCase(customerTypeName)) {
                    List<CustomerAddressPojo> addressPojos = pojo.getAddressList();
                    addressPojos = addressPojos.stream().filter(x -> x.getVersion().equalsIgnoreCase("New")).collect(Collectors.toList());
                    pojo.setAddressList(addressPojos);
                }

                long childCustCount = customersService.getChildCustomerCount(pojo.getId(), CommonConstants.INVOICE_TYPE_GROUP);
                pojo.setHasChildCust(childCustCount > 0);
                List<Long> locationIds = customerLocationRepository.findAllLocationIdsByCustomer(Long.valueOf(pojo.getId()));
                if (!CollectionUtils.isEmpty(locationIds)) {
                    pojo.setLocations(locationIds);
                }
                //fetch mac retention date
                List<Timestamp> macRetentionDate = custMacMapppingRepository.findNearestMacRetentionDateByCustomerId(id);
                if (!CollectionUtils.isEmpty(macRetentionDate)) {
                    if (macRetentionDate.get(0) != null) {
                        pojo.setNearestMacRetentionDate(macRetentionDate.get(0).toLocalDateTime().toLocalDate());
                    }
                }
                //fetch quota reset date;
                if (!CollectionUtils.isEmpty(pojo.getPlanMappingList())) {
                    LocalDateTime now = LocalDateTime.now();
                    Optional<CustPlanMapppingPojo> custPlanMappping = pojo.getPlanMappingList().stream()
                            .filter(plan -> "Active".equalsIgnoreCase(plan.getCustPlanStatus()) &&
                                    plan.getPurchaseType() != null &&
                                    !plan.getPurchaseType().equalsIgnoreCase("Volume Booster") &&
                                    !plan.getPurchaseType().equalsIgnoreCase("Bandwidthbooster") &&
                                    (plan.getStartDate().isBefore(now) || plan.getStartDate().isEqual(now)) &&
                                    (plan.getEndDate().isAfter(now) || plan.getEndDate().isEqual(now))).findFirst();
                    if (custPlanMappping.isPresent()) {
                        LocalDate quotaResetDate = custQuotaService.fincNearestQuotaResetDateUsingCprId(custPlanMappping.get().getId());
                        pojo.setQuotaResetDate(quotaResetDate);
                    }
                }
                response.put("customers", pojo);
                RESP_CODE = APIConstants.SUCCESS;
//                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, req.getRemoteAddr(), null, customers.getId().longValue(), customers.getFullName());
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }

        } catch (CustomValidationException ce) {

            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers by id: " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

    @PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_CUSTOMER_ALL + "\",\"" + AclConstants.OPERATION_CUSTOMER_VIEW + "\")")
    @PutMapping("/customers/updateIsTrialValidityDays")
    public ResponseEntity<?> updateIsTrialValidityDays(@RequestParam(name = "custpackid") Integer custpackid, @RequestParam(name = "isTrialValidityDays") Double isTrialValidityDays, @RequestParam(name = "istrialplan") Boolean istrialplan) {

        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            BusinessUnit businessUnit = new BusinessUnit();
            if (getBUIdsFromCurrentStaff().size() == 1) {
                businessUnit = businessUnitRepository.findById(getBUIdsFromCurrentStaff().get(0)).get();
            } else if (getBUIdsFromCurrentStaff().size() == 0) {
                businessUnit.setPlanBindingType("");
            }

            CustPlanMappping custPlanMappping = custPlanMappingRepository.findById(custpackid);
            // TODO: pass mvnoID manually 6/5/2025
            Double trialPlanPeirodConstant = Double.valueOf(clientServiceSrv.getByNameAndMvnoIdEquals(Constants.TRIAL_PLAN_PERIOD_THRESHOLD, getMvnoIdFromCurrentStaff(null)).getValue());
            // TODO: pass mvnoID manually 6/5/2025
            Integer tpValidityCount = Integer.valueOf(clientServiceSrv.getByNameAndMvnoIdEquals(Constants.ALLOW_NUMBER_OF_TIME_TRAIL, getMvnoIdFromCurrentStaff(null)).getValue());
            Integer countOfValidity = custPlanMappping.getTrialPlanValidityCount();
            Double tpvDays = custPlanMappping.getIsTrialValidityDays() + isTrialValidityDays;
            if (istrialplan && (businessUnit.getPlanBindingType().equalsIgnoreCase("On-Demand"))) {
                if (isTrialValidityDays <= trialPlanPeirodConstant && tpvDays <= trialPlanPeirodConstant && custPlanMappping.getTrialPlanValidityCount() < tpValidityCount) {
                    custPlanMappping.setIsTrialValidityDays(tpvDays);
                    custPlanMappping.setIstrialplan(true);
                    custPlanMappping.setEndDate(custPlanMappping.getEndDate().plusDays((long) (isTrialValidityDays - 1)));
                    custPlanMappping.setExpiryDate(custPlanMappping.getExpiryDate().plusDays((long) (isTrialValidityDays - 1)));
                    countOfValidity = countOfValidity + 1;
                    custPlanMappping.setTrialPlanValidityCount(countOfValidity);

                    CustPlanMappping custPlanMappping1 = custPlanMappingRepository.save(custPlanMappping);
                    response.put("custPlanMappping", custPlanMappping1);
                    RESP_CODE = APIConstants.SUCCESS;
                } else if (isTrialValidityDays > trialPlanPeirodConstant || tpvDays > trialPlanPeirodConstant || custPlanMappping.getTrialPlanValidityCount() >= tpValidityCount) {
                    throw new CustomValidationException(APIConstants.FAIL, "Trial Plan Period Validity cannot be extended more than 3 times or 90 days..", null);
                }
            } else if (!istrialplan) {
                throw new CustomValidationException(APIConstants.FAIL, "Please mark plan as Trial Plan first...", null);
            }
        } catch (CustomValidationException ce) {

            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
        }
        MDC.remove("type");
        return apiResponse(RESP_CODE, response);

    }

