    @GetMapping("/invoiceserver")
    public ResponseEntity<?> getActiveInvoiceServerList(HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());

        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            InvoiceServerService invoiceServerService = SpringContext.getBean(InvoiceServerService.class);
            List<InvoiceServer> invoiceserverList = invoiceServerService.getAllActiveEntities();

            for (InvoiceServer invoiceServer : invoiceserverList) {
                String webPort = invoiceServer.getWebport();
                String serverIP = invoiceServer.getServerip();
                String strUR = "http://" + serverIP + ":" + webPort + "/billing-engine-1.0/billingprocess/statuscheck";
                String respose = null;
                try {
                    RestTemplate restTemplate = new RestTemplate();
                    respose = restTemplate.getForObject(strUR, String.class);
                } catch (Exception e) {
                    ///			ApplicationLogger.logger.error(MODULE + e.getStackTrace(), e);
                    invoiceServer.setStatus("0");
                    log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All invoiceserver list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                }
                if (respose != null && respose.contains("{\"responseCode\":\"200\",\"responseMessage\":\"Success\",\"responseObject\":null}")) {
                    invoiceServer.setStatus("1");
                } else {
                    invoiceServer.setStatus("0");
                }
            }
            response.put("invoiceserverList", invoiceServerService.convertResponseModelIntoPojo(invoiceserverList));
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All invoiceserver list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All invoiceserver list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All invoiceserver list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

