    @GetMapping("/system/configuration" + UrlConstants.CLEAR_CACHE)
    public GenericDataDTO clearCache(HttpServletRequest req) {
        String SUB_MODULE = "[clearCache]";
        Integer RESP_CODE = APIConstants.FAIL;
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        genericDataDTO.setResponseCode(HttpStatus.OK.value());
        genericDataDTO.setResponseMessage("Success");
        try {
            //		ApplicationLogger.logger.info(SUB_MODULE);
            cacheManager.getCache(CacheConstant.CLIENT_SRV).clear();
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "System Configurations Clear cache" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            return genericDataDTO;
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(SUB_MODULE + ex.getStackTrace(), ex);
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            genericDataDTO.setResponseCode(HttpStatus.EXPECTATION_FAILED.value());
            genericDataDTO.setResponseMessage("Failed to clear cache");
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "System Configurations Clear cache" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        }
        MDC.remove("type");
        return genericDataDTO;
    }

