    @PostMapping("/invoice/search")
    public ResponseEntity<?> searchInvoice(@ModelAttribute SearchDebitDocsPojo entity, @RequestBody PaginationRequestDTO requestDTO, HttpServletRequest req, @RequestParam(name = "isInvoiceVoid", defaultValue = "true") boolean isInvoiceVoid) {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Search");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        Page<DebitDocSearchPojo> debitDocList = null;
        try {
            if (entity != null) {
                DebitDocService debitDocService = SpringContext.getBean(DebitDocService.class);
                requestDTO = setDefaultPaginationValues(requestDTO);
                debitDocList = debitDocService.searchInvoice(entity, requestDTO, isInvoiceVoid);
                if (null != debitDocList && 0 < debitDocList.getSize()) {
                    response.put("invoicesearchlist", debitDocList.getContent());
                } else {
                    response.put("invoicesearchlist", new ArrayList<>());
                }
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search invoicesearchlist using keyword " + entity.getCustname() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search invoicesearchlist using keyword " + entity.getCustname() + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception e) {
            //		ApplicationLogger.logger.error(MODULE + e.getStackTrace(), e);
            e.printStackTrace();
            RESP_CODE = APIConstants.INTERNAL_SERVER_ERROR;
            response.put(APIConstants.ERROR_TAG, HttpStatus.INTERNAL_SERVER_ERROR.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search invoicesearchlist using keyword " + entity.getCustname() + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, debitDocList);
    }

