    @PreAuthorize("validatePermission(\"" + MenuConstants.DUNNING_RULES_DELETE + "\")")
    @DeleteMapping("/dunningrule/{id}")
    public ResponseEntity<?> deleteDunningRule(@PathVariable Integer id, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Delete");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        DunningRule drule = new DunningRule();
        try {
            DunningRuleService dunningRuleService = SpringContext.getBean(DunningRuleService.class);
            DunningRule dunningRule = dunningRuleService.getEntityForUpdateAndDelete(id,mvnoId);
            if (dunningRule != null) {
                DunningRulePojo pojo = dunningRuleService.convertDunningRuleModelToDunningRulePojo(dunningRule);
                dunningRuleService.validateRequest(pojo, CommonConstants.OPERATION_DELETE);
                dunningRuleService.deleteDunningRule(id,mvnoId);
                response.put(CommonConstants.RESPONSE_MESSAGE, messagesProperty.get("api.dunningrule.deleted"));
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete dunningrule" + LogConstants.LOG_BY_NAME + dunningRuleService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete dunningrule" + LogConstants.LOG_BY_NAME + dunningRuleService.get(id,mvnoId).getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.object.not.found"), null);
            }

        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete dunningrule" + LogConstants.LOG_BY_NAME + drule.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete dunningrule" + LogConstants.LOG_BY_NAME + drule.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

