    @GetMapping("/user/search")
    public ResponseEntity<?> searchUser(@RequestParam(name = "s", defaultValue = "") String search) throws Exception {
        MDC.put("type", "fetch");
        StaffUserService staffUserService = SpringContext.getBean(StaffUserService.class);
        HashMap<String, Object> response = new HashMap<>();
        List<StaffUserPojo> user = null;
        if ("".equals(search)) {
            user = staffUserService.convertResponseModelIntoPojo(staffUserService.getAllActiveEntities());
            response.put("items", user);
        } else {
            user = staffUserService.searchUserCustom(search);
            response.put("items", user);
        }
        return apiResponse(APIConstants.SUCCESS, response);
    }

    @GetMapping("/staff/search")
    public GenericDataDTO searchStaff(@RequestParam(name = "s", defaultValue = "") String search, HttpServletRequest req, @RequestBody PaginationRequestDTO requestDTO) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Search");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        String SUBMODULE = MODULE + " [searchStaff()] ";
        StaffUserService staffUserService = SpringContext.getBean(StaffUserService.class);
        try {
            if ("".equals(search)) {
                genericDataDTO.setResponseCode(HttpStatus.NOT_ACCEPTABLE.value());
                genericDataDTO.setResponseMessage("Please provide search criteria!");
                Integer RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search staff using keyword " + requestDTO.getFilters().get(0).getFilterValue() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                return genericDataDTO;
            }
            return GenericDataDTO.getGenericDataDTO(staffUserService.searchStaff(search));
        } catch (Exception ex) {
            ///		ApplicationLogger.logger.error(SUBMODULE + ex.getStackTrace(), ex);
            genericDataDTO.setResponseCode(HttpStatus.EXPECTATION_FAILED.value());
            genericDataDTO.setResponseMessage(HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            Integer RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "search staff using keyword" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            return genericDataDTO;
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
    }

