    @GetMapping("/entity")
    public ResponseEntity<?> getAllClass(@RequestParam(name = "s", defaultValue = "") String search, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        AuditService auditService = SpringContext.getBean(AuditService.class);
        HashMap<String, Object> response = new HashMap<>();
        if ("".equals(search)) {
            response.put("items", auditService.getAllEntityPojo());
        } else {
            List<EntityPojo> result = auditService.getAllEntityPojo().stream().filter(item -> item.getClassName().equalsIgnoreCase(search)).collect(Collectors.toList());
            response.put("items", result);
        }
        MDC.remove("type");
        Integer RESP_CODE = APIConstants.SUCCESS;
        log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch all classes" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        return apiResponse(APIConstants.SUCCESS, response);
    }

