    @GetMapping("/plans")
    public ResponseEntity<?> getCustPlans(@RequestParam Integer id, HttpServletRequest req) {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        CustQuotaService custQuotaService = SpringContext.getBean(CustQuotaService.class);
        CustPlanMappingService custPlanMappingService = SpringContext.getBean(CustPlanMappingService.class);
        PostpaidPlanService postpaidPlanService = SpringContext.getBean(PostpaidPlanService.class);
        try {
            List<CustQuotaDtlsPojo> quotaDtlsDTOList = custQuotaService.findAllByCustomersId(id);
            List<CustPlanMapppingPojo> custPlanMapppings = custPlanMappingService.findAllByCustomersId(id);
            List<ServicePlansPojo> servicePlansDTOList = new ArrayList<>();
            for (int i = 0; i < quotaDtlsDTOList.size() || i < custPlanMapppings.size(); i++) {
                ServicePlansPojo servicePlansPojo = new ServicePlansPojo();
                if (i < quotaDtlsDTOList.size()) {
                    CustQuotaDtlsPojo quotaDtlsDTO = quotaDtlsDTOList.get(i);
                    servicePlansPojo.setPlanId(quotaDtlsDTO.getPlanId());
                    servicePlansPojo.setPlanName(postpaidPlanService.findNameById(quotaDtlsDTO.getPlanId()));
                    servicePlansPojo.setQuotaType(quotaDtlsDTO.getQuotaType());
                    servicePlansPojo.setDataTotalQuota(quotaDtlsDTO.getTotalQuota());
                    servicePlansPojo.setDataUsedQuota(quotaDtlsDTO.getUsedQuota());
                    servicePlansPojo.setDataQuotaUnit(quotaDtlsDTO.getQuotaUnit());
                    servicePlansPojo.setTimeTotalQuota(quotaDtlsDTO.getTimeTotalQuota());
                    servicePlansPojo.setTimeUsedQuota(quotaDtlsDTO.getTimeQuotaUsed());
                    servicePlansPojo.setTimeQuotaUnit(quotaDtlsDTO.getTimeQuotaUnit());
                }

                if (i < custPlanMapppings.size()) {
                    CustPlanMapppingPojo custPlanMapppingPojo = custPlanMapppings.get(i);
                    servicePlansPojo.setExpiry(custPlanMapppingPojo.getExpiryDate().toLocalDate());
                    servicePlansPojo.setQosPolicyId(custPlanMapppingPojo.getQospolicyId());
                }
                servicePlansDTOList.add(servicePlansPojo);
            }
            response.put("plans", servicePlansDTOList);
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All plans list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All plans list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);FT
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All plans list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

