    public PaginationRequestDTO setDefaultPaginationValues(PaginationRequestDTO requestDTO) {
        PAGE = Integer.parseInt(clientServiceSrv.getClientSrvByName(ClientServiceConstant.DEFAULT_PAGE).get(0).getValue());
        PAGE_SIZE = Integer.parseInt(clientServiceSrv.getClientSrvByName(ClientServiceConstant.DEFAULT_PAGE_SIZE).get(0).getValue());
        SORT_BY = clientServiceSrv.getClientSrvByName(ClientServiceConstant.DEFAULT_SORTBY).get(0).getValue();
        SORT_ORDER = Integer.parseInt(clientServiceSrv.getClientSrvByName(ClientServiceConstant.DEFAULT_SORT_ORDER).get(0).getValue());
        MAX_PAGE_SIZE = Integer.parseInt(clientServiceSrv.getClientSrvByName(ClientServiceConstant.MAX_PAGE_SIZE).get(0).getValue());

        if (null == requestDTO.getPage()) requestDTO.setPage(PAGE);
        if (null == requestDTO.getPageSize()) requestDTO.setPageSize(PAGE_SIZE);
        if (null == requestDTO.getSortBy()) requestDTO.setSortBy(SORT_BY);
        if (null == requestDTO.getSortOrder()) requestDTO.setSortOrder(SORT_ORDER);
        if (null != requestDTO.getPageSize() && requestDTO.getPageSize() > MAX_PAGE_SIZE)
            requestDTO.setPageSize(MAX_PAGE_SIZE);
        return requestDTO;
    }

    @PostMapping("/checkPartnerUniqueEmail")
    public GenericDataDTO checkPartnerUniqueEmail(@Valid @RequestBody PartnerEmailUniqueChequeReqDTO reqDTO, BindingResult result, HttpServletRequest req) {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        String SUBMODULE = MODULE + " [checkPartnerUniqueEmail()] ";
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        try {
            if (null == reqDTO) {
                genericDataDTO.setResponseCode(HttpStatus.NOT_ACCEPTABLE.value());
                genericDataDTO.setResponseMessage("Please Provide Request Parameter");
                Integer RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Partner Email" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_UNAUTHORIZED + LogConstants.LOG_ERROR + "Access denined for update operation " + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }
            if (null != reqDTO) {
                if (null != reqDTO.getValue() && partnerService.checkPartnerUniqueEmail(reqDTO.getValue(), reqDTO.getPartnerId())) {
                    genericDataDTO.setResponseCode(HttpStatus.NOT_ACCEPTABLE.value());
                    genericDataDTO.setResponseMessage("Email already exists!");
                    Integer RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                    log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Partner Email" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_UNAUTHORIZED + LogConstants.LOG_ERROR + "Access denined for update operation " + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                    return genericDataDTO;
                }
                genericDataDTO.setResponseMessage(HttpStatus.OK.getReasonPhrase());
                genericDataDTO.setResponseCode(HttpStatus.OK.value());
                Integer RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Partner Email " + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }
        } catch (Exception e) {
            //		ApplicationLogger.logger.error(SUBMODULE + e.getStackTrace(), e);
            genericDataDTO.setResponseMessage(HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            genericDataDTO.setResponseCode(HttpStatus.EXPECTATION_FAILED.value());
            Integer RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch Partner Email" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return genericDataDTO;
    }

    @PutMapping("/approveCaf")
    public ResponseEntity<?> assignCustomerCaf(@RequestBody CustomerCafAssignmentPojo pojo, HttpServletRequest req ,
                                               @RequestParam("mvnoId") Integer mvnoId) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Update");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        CafDto cafDto = null;
        String userName = customersRepository.findCustomerName(pojo.getCustcafId());

        try {
            Customers customers = customersRepository.findById(pojo.getCustcafId()).orElse(null);
            if(customers!=null){
                if(!customers.getServicearea().getStatus().equalsIgnoreCase(BulkManagementConstant.DropdownStatus.UNDER_DEVELOPMENT)){
                    CustomerCafAssignmentService customerCafAssignmentService = SpringContext.getBean(CustomerCafAssignmentService.class);
                    if (pojo != null) {
                        cafDto = customersService.updateCustomerCafAssignment(pojo, req,mvnoId);
                        if (cafDto.getCustomers() != null && cafDto.getCustomers().getCafApproveStatus() != null) {
                            CaftoCustomerMessage caftoCustomerMessage = new CaftoCustomerMessage();
                            caftoCustomerMessage.setCustomerId(cafDto.getCustomers().getId());
                            caftoCustomerMessage.setLoggedInUser(getLoggedInUserId());
                            caftoCustomerMessage.setStatus(cafDto.getCustomers().getStatus());
                            caftoCustomerMessage.setCafApproveStatus(cafDto.getCustomers().getCafApproveStatus() != null ? cafDto.getCustomers().getCafApproveStatus() : null);
                            if (cafDto.getCustomers() != null && cafDto.getCustomers().getCustomerServiceMappingList() != null && !cafDto.getCustomers().getCustomerServiceMappingList().isEmpty() && cafDto.getCustomers().getCustomerServiceMappingList().get(0) != null) {
                                if (cafDto.getCustomers().getCustomerServiceMappingList().get(0).getDiscountType() != null
                                        && cafDto.getCustomers().getCustomerServiceMappingList().get(0).getDiscountType().equalsIgnoreCase("one-time")
                                        && cafDto.getCustomers().getCustomerServiceMappingList().get(0).getDiscountExpiryDate() != null) {
                                    caftoCustomerMessage.setDiscountexpdate(cafDto.getCustomers().getCustomerServiceMappingList().get(0).getDiscountExpiryDate().toString());
                                }
                            }
//                       messageSender.send(caftoCustomerMessage, SharedDataConstants.QUEUE_CAF_TO_CUSTOMER_DATA_SHARE_REVENUE);
                            kafkaMessageSender.send(new KafkaMessageData(caftoCustomerMessage, CaftoCustomerMessage.class.getSimpleName()));

                        }
                        // TODO: pass mvnoID manually 6/5/2025
                        String nmsEnable = clientServiceRepository.findValueByNameAndMvnoId(NMSIntegrationConstants.NMS_INTEGRATION.NMS_INTEGRATION_ENABLE, customers.getMvnoId());
                        if (cafDto.getCustomers() != null && cafDto.getCustomers().getStatus().equalsIgnoreCase(SubscriberConstants.ACTIVATION_PENDING) && nmsEnable != null && nmsEnable.equalsIgnoreCase(NMSIntegrationConstants.NMS_INTEGRATION.TRUE_FLAG)) {
                            response.put("result", cafDto.getGenericDataDTO());
                            response.put("message", "NMS Integration API Failed");
                            RESP_CODE = APIConstants.EXPECTATION_FAILED;
                            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update caf" + LogConstants.LOG_BY_NAME + userName + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + "NMS Integration API Failed" + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                        }
                        else if (cafDto.getGenericDataDTO() != null
                                && Objects.nonNull(cafDto.getGenericDataDTO().getResponseCode())
                                && HttpStatus.EXPECTATION_FAILED.value() == cafDto.getGenericDataDTO().getResponseCode()){
                            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
                            response.put("message", cafDto.getGenericDataDTO().getResponseMessage());
                            response.put(APIConstants.ERROR_TAG, cafDto.getGenericDataDTO().getResponseMessage());
                        }else {
                            response.put("result", cafDto.getGenericDataDTO());
                            response.put("message", "Successfully updated");
                            RESP_CODE = APIConstants.SUCCESS;
                            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update caf" + LogConstants.LOG_BY_NAME + userName + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                        }
//                Runnable chargeRunnable1 = new InvoiceCreationThread(customerMapper.domainToDTO(cafDto.getCustomers(), new CycleAvoidingMappingContext()), cafDto.getCustomersService(), null, false, null, CommonConstants.INVOICE_TYPE.RENEW);
//                Thread billchargeThread1 = new Thread(chargeRunnable1);
//                billchargeThread1.start();
                    }
                }else{
                    customersService.validateServiceArea(customers);
                }
            }

        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put("message", ce.getMessage());
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update caf" + LogConstants.LOG_BY_NAME + userName + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update caf" + LogConstants.LOG_BY_NAME + userName + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
            return apiResponse(RESP_CODE, response);
        }
//        return apiResponse(RESP_CODE, response);
    }

    @DeleteMapping("/mvno/delete/{id}")
    public ResponseEntity<?> deleteMvno(@PathVariable Long id, HttpServletRequest req,@RequestParam("mvnoId") Integer mvnoId
    ) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Delete");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        HashMap<String, Object> response = new HashMap<>();
        MvnoDTO mvnoDt = new MvnoDTO();
        try {
            MvnoService countryService = SpringContext.getBean(MvnoService.class);
            MvnoDTO dto = countryService.getEntityById(id,mvnoId);
            if (dto != null) {
                countryService.getRepository().deleteById(id);
                response.put(CommonConstants.RESPONSE_MESSAGE, "Mvno is deleted.");
                RESP_CODE = APIConstants.SUCCESS;
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_COUNTRY, AclConstants.OPERATION_COUNTRY_DELETE, req.getRemoteAddr(), null, dto.getId().longValue(), dto.getName());
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete Mvno" + LogConstants.LOG_BY_NAME + mvnoDt.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "delete Mvno" + LogConstants.LOG_BY_NAME + mvnoDt.getName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                throw new CustomValidationException(APIConstants.FAIL, messagesProperty.get("api.object.not.found"), null);
            }

        } catch (CustomValidationException ce) {
            ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
        } catch (Exception ex) {
            if (ex instanceof RuntimeException) {
                ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                RESP_CODE = HttpStatus.METHOD_NOT_ALLOWED.value();
                response.put(APIConstants.ERROR_TAG, ex.getMessage());
            } else {
                ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
                ex.printStackTrace();
                RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
                response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            }
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

