    @PreAuthorize("validatePermission(\"" + MenuConstants.PrepaidCustomers.PREPAID_CUSTOMER_SEND_PAYMENT_LINK + "\",\"" + MenuConstants.PrepaidCustomerCAF.PREPAID_CAF_CUSTOMER_SEND_PAYMENT_LINK + "\",\"" + MenuConstants.PostpaidCustomerCAF.POSTPAID_CAF_CUSTOMER_SEND_PAYMENT_LINK + "\",\"" + MenuConstants.PostpaidCustomers.POSTPAID_CUSTOMER_SEND_PAYMENT_LINK + "\")")
    @PostMapping(value = "/generatePaytmLinkAndSend")
    public ResponseEntity<?> createPaytmLinkAndSendToCustomer(@RequestParam(name = "custId", required = true) Integer custId) {
        MDC.put("type", "Create");
        HashMap<String, Object> response = new HashMap<>();
        Integer RESP_CODE = APIConstants.SUCCESS;
        try {
            if (custId != null) {
                Customers customer = customersService.getById(custId);
                if (customer != null) {
                    List<CustomerLedger> ledger = customerLedgerRepository.findByCustomer(customer);
                    if (clientServiceSrv.getByNameAndMvnoId("paytmlinksms_enable",customer.getMvnoId()).getValue().equals("true")) {
                        if (ledger != null && ledger.size() > 0 && ledger.get(0).getTotaldue() > 0) {
                            CustomerPaymentDto customerPaymentDto = new CustomerPaymentDto();
                            customerPaymentDto.setCustId(custId);
                            customerPaymentDto.setStatus(CommonConstants.PAYMENT_INITIATE);
                            customerPaymentDto.setPayment(ledger.get(0).getTotaldue());
                            Long orderId = Long.valueOf(customersService.addPaymentStatus(customerPaymentDto).getOrderId());
                            String linkUrl = customersService.getPaymentUrl(orderId, ledger.get(0).getTotaldue(), customer);
                            Shorter shorter = shorterService.createShortUrl(linkUrl, custId, ledger.get(0).getTotaldue(),null,null,null);
                            if (shorter != null) {
                                String shortUrl = clientServiceSrv.getByName("paymentIpAddress").getValue() + ":30080/api/v1/payment/" + shorter.getHash();
                                response.put("PaymentUrl", shortUrl);
                                customersService.sendCustPaymentLinkMessage("payment link", customer.getUsername(), ledger.get(0).getTotaldue(), shortUrl, 1, customer.getCountryCode(), customer.getMobile(), customer.getEmail(),(long) customersService.getLoggedInStaffId());

                            } else
                                //			logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;", MODULE,RESP_CODE,response);
                                throw new Exception();
                        } else {
                            RESP_CODE = APIConstants.FAIL;
                            response.put("msg", "No Payment is Due");
                            //logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;", MODULE,RESP_CODE,response);
                            return apiResponse(RESP_CODE, response);
                        }
                    } else {
                        RESP_CODE = APIConstants.FAIL;
                        response.put("msg", "PaytmLinkSms configuration is disable at serverside");
                        //logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;", MODULE,RESP_CODE,response);
                        return apiResponse(RESP_CODE, response);
                    }
                } else {
                    RESP_CODE = APIConstants.FAIL;
                    response.put("msg", "Customer not found");
                    //logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;", MODULE,RESP_CODE,response);
                    return apiResponse(RESP_CODE, response);
                }
            } else {
                RESP_CODE = APIConstants.FAIL;
                response.put("msg", "Invalid Customer Id");
                //logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;", MODULE,RESP_CODE,response);
                return apiResponse(RESP_CODE, response);
            }
        } catch (Exception e) {
            RESP_CODE = APIConstants.FAIL;
            response.put("msg", "Link Creation failed");
            //	logger.error("Unable to create PaytmLink And Send To Customer "+customersService.get(custId).getUsername()+":  request: { From : {}}; Response : {{}};Error :{} ;Exxception:{}", MODULE,RESP_CODE,response,e.getStackTrace());
            return apiResponse(RESP_CODE, response);
        }

        //logger.info("Payment link for customer  "+customersService.get(custId).getUsername()+"  is Successfully sent   :  request: { From : {}}; Response : {{]}",MODULE,RESP_CODE,response);
        //MDC.remove("type");
        //response.put("msg", "Paytm Link sent Successfully");
        return apiResponse(RESP_CODE, response);
    }

    @GetMapping(path = "/payment/{hash}")
    public ResponseEntity redirectShorter(@PathVariable("hash") String hash) {
        Shorter shorter = shorterRepository.findByHash(hash).orElse(null);
        if (shorter != null) {
            Customers customer = customersService.getById(shorter.getCustId());
            if (customer != null) {
                List<CustomerLedger> ledger = customerLedgerRepository.findByCustomer(customer);
                if (ledger.get(0).getTotaldue() <= 0) return ResponseEntity.notFound().build();
                else
                    return ResponseEntity.status(HttpStatus.FOUND).location(URI.create(shorter.getOriginalUrl())).build();
            }
        }
        return ResponseEntity.notFound().build();
    }

    @PostMapping("/customers/list")
    public ResponseEntity<?> getAllCustomers(@RequestBody PaginationRequestDTO requestDTO,@RequestParam("mvnoId") Integer mvnoId, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Page<Customers> pageRes = null;
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            CustomersService customerService = SpringContext.getBean(CustomersService.class);
            requestDTO = setDefaultPaginationValues(requestDTO);
//			if(requestDTO.getSortBy().equalsIgnoreCase("id"))
//				requestDTO.setSortBy("custid");
            pageRes = subscriberService.getListFromCustomer(requestDTO.getPage(), requestDTO.getPageSize(), "id", -1, requestDTO.getFilters(),mvnoId);
            if (null != pageRes && 0 < pageRes.getSize()) {
                response.put("customerList", pageRes.stream().map(data -> {
                    try {
                        return subscriberDetailsMapper.domainToDTO(data, new CycleAvoidingMappingContext());
                    } catch (NoSuchFieldException e) {
                        final Integer RESPCODE = APIConstants.FAIL;
                        log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All Customers list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESPCODE);
                        e.printStackTrace();
                    }

                    return null;
                }).collect(Collectors.toList()));
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, req.getRemoteAddr(), null, null, "");

            } else response.put("customerList", new ArrayList<>());
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All Customers list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All Customers list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch All Customers list" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, pageRes);
    }

