    @PostMapping(value = "/submitPaymentDetail/captivePortal")
    public ResponseEntity<?> getRedirectCaptivePortal(@Valid @RequestBody PaytmPaymentDto paytmPaymentDto, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        try {
            Integer RESP_CODE = APIConstants.SUCCESS;
            HashMap<String, Object> response = new HashMap<>();
            Integer mvnoId = getMvnoIdFromCurrentStaff(paytmPaymentDto.getCustId());
            if (clientServiceSrv.getValueByName(ClientServiceConstant.PAYEMNT_GATEWAY,mvnoId).equals(ClientServiceConstant.PAYTM)) {
                ModelAndView modelAndView = new ModelAndView("redirect:" + clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_URL,mvnoId));
                TreeMap<String, String> parameters = new TreeMap<>();
                parameters.put("CHANNEL_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CHANNEL_ID,mvnoId));
                parameters.put("INDUSTRY_TYPE_ID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_INDUSTRY_TYPE_ID,mvnoId));
                parameters.put("MID", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_MERCHANT_ID,mvnoId));
                parameters.put("WEBSITE", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_WEBSITE,mvnoId));
                parameters.put("CALLBACK_URL", clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_CALLBACK_URL,mvnoId));

                Customers customer = customersService.getById(paytmPaymentDto.getCustId());
                if (customer != null) parameters.put("EMAIL", customer.getEmail());
                parameters.put("MOBILE_NO", paytmPaymentDto.getMobileNo().toString());
                parameters.put("ORDER_ID", paytmPaymentDto.getOrderId().toString());
                parameters.put("TXN_AMOUNT", paytmPaymentDto.getTxnAmount().toString());
                parameters.put("CUST_ID", paytmPaymentDto.getCustId().toString());
                String checkSum = getCheckSum(parameters, mvnoId);
                parameters.put("CHECKSUMHASH", checkSum);

                modelAndView.addAllObjects(parameters);
                HttpUriRequest httpGetForAccessToken = RequestBuilder.get().setUri(new URI(clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_URL,mvnoId))).addParameter("CHANNEL_ID", parameters.get("CHANNEL_ID")).addParameter("CHECKSUMHASH", checkSum).addParameter("ORDER_ID", paytmPaymentDto.getOrderId().toString()).addParameter("TXN_AMOUNT", paytmPaymentDto.getTxnAmount().toString()).addParameter("CUST_ID", paytmPaymentDto.getCustId().toString()).addParameter("INDUSTRY_TYPE_ID", parameters.get("INDUSTRY_TYPE_ID")).addParameter("CHANNEL_ID", parameters.get("CHANNEL_ID")).addParameter("MID", parameters.get("MID")).addParameter("MOBILE_NO", paytmPaymentDto.getMobileNo().toString()).addParameter("EMAIL", (customer != null) ? customer.getEmail() : "").addParameter("WEBSITE", parameters.get("WEBSITE")).addParameter("CALLBACK_URL", clientServiceSrv.getByName("paymentIpAddress").getValue() + ":30080/paytm/pgresponse").build();
                String url = clientServiceSrv.getValueByName(ClientServiceConstant.PAYTM_PAYMENT_URL,mvnoId) + "?CHANNEL_ID=" + parameters.get("CHANNEL_ID") + "&CUST_ID=" + paytmPaymentDto.getCustId() + "&EMAIL=" + customer.getEmail() + "&INDUSTRY_TYPE_ID=" + parameters.get("INDUSTRY_TYPE_ID") + "&MID=" + parameters.get("MID") + "&MOBILE_NO=" + paytmPaymentDto.getMobileNo() + "&ORDER_ID=" + paytmPaymentDto.getOrderId() + "&TXN_AMOUNT=" + paytmPaymentDto.getTxnAmount() + "&WEBSITE=" + parameters.get("WEBSITE") + "&CHECKSUMHASH=" + checkSum + "&CALLBACK_URL=" + clientServiceSrv.getByName("paymentIpAddress").getValue() + ":30080/paytm/pgresponse";
                response.put("paytmRedirectUrl", httpGetForAccessToken.getURI().toString());
                response.put("paytmRedirectUrl2", url);
            } else if (clientServiceSrv.getValueByName(ClientServiceConstant.PAYEMNT_GATEWAY,mvnoId).equals(ClientServiceConstant.FLUTTER_WAVE)) {

                JSONObject jsonObject = new JSONObject();
                jsonObject.put("tx_ref", paytmPaymentDto.getOrderId());
                jsonObject.put("amount", paytmPaymentDto.getTxnAmount());
                jsonObject.put("currency", clientServiceSrv.getValueByName(ClientServiceConstant.CURRENCY_FOR_PAYMENT,mvnoId));
                jsonObject.put("redirect_url", clientServiceSrv.getValueByName(ClientServiceConstant.PAYMENT_REDIRECT_URL_CAPTIVE_PORTAL,mvnoId));
                jsonObject.put("meta", new JSONObject().put("consumer_id", paytmPaymentDto.getCustId()));
                jsonObject.put("customer", new JSONObject().put("email", paytmPaymentDto.getCustomerEmail()).put("phonenumber", paytmPaymentDto.getMobileNo()).put("name", paytmPaymentDto.getCustomerName()));
                HttpUriRequest httpGetForAccessToken = RequestBuilder.post().setUri(new URI(clientServiceSrv.getValueByName(ClientServiceConstant.FLUTTER_WAVE_PAYMENT_URL,mvnoId))).setHeader("Authorization", "Bearer " + clientServiceSrv.getValueByName(ClientServiceConstant.FLW_SECRET_KEY,mvnoId)).setEntity(new StringEntity(String.valueOf(jsonObject), ContentType.APPLICATION_JSON)).build();

                CloseableHttpClient client = HttpClients.createDefault();
                CloseableHttpResponse result = client.execute(httpGetForAccessToken);
                HttpEntity entity = result.getEntity();
                String content = EntityUtils.toString(entity);
                JSONObject json = (JSONObject) new JSONObject(content).get("data");
                response.put("paytmRedirectUrl", json.get("link"));
//                response.put("paytmRedirectUrl2", "");
            }
//            response.put("parameters", parameters);
            MDC.remove("type");
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch getRedirectCaptivePortal" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            return apiResponse(RESP_CODE, response);

        } catch (Exception e) {
            Integer RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch getRedirectCaptivePortal" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            //e.printStackTrace();
            return null;
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
    }

