    //@PreAuthorize("validatePermission(\"" + AclConstants.OPERATION_PLAN_GROUP_ALL + "\",\"" + AclConstants.OPERATION_PLAN_GROUP_ADD + "\")")
    @PreAuthorize("validatePermission(\"" + MenuConstants.PLAN_GROUP_CREATE + "\")")
    @PostMapping("/addPlanGroup")
    public ResponseEntity<?> addPlanGroup(@Valid @RequestBody PlanGroupDTO planGroupDTO, HttpServletRequest req) {
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Create");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        try {
            PlanGroup planGroup = new PlanGroup();
            planGroupService.validatePlanGroup(planGroupDTO, CommonConstants.OPERATION_ADD);
            boolean flag = planGroupService.duplicateVerifyAtSave(planGroupDTO.getPlanGroupName(),planGroupDTO.getMvnoId());
            boolean isSameStaff = planGroupService.isSameStaff(planGroupDTO.getPlanGroupName(),planGroupDTO.getMvnoId());
            if (flag) {
                if (getBUIdsFromCurrentStaff() != null && getBUIdsFromCurrentStaff().size() > 1)
                    throw new CustomValidationException(APIConstants.FAIL, Constants.AVOID_SAVE_MULTIPLE_BU, null);
                planGroup = planGroupService.savePlanGroup(planGroupDTO, planGroupDTO.getMvnoId());  // TODO: pass mvnoID manually 6/5/2025
                planGroupService.sendCreateDataShared(planGroup, CommonConstants.OPERATION_ADD);
                response.put("planGroup", planGroup);
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create planGroup" + LogConstants.LOG_BY_NAME + planGroupDTO.getPlanGroupName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                String errMsg;
                if (!isSameStaff) {
                    errMsg = MessageConstants.PLAN_GROUP_NAME_EXITS_DIFF_STAFF;
                } else {
                    errMsg = MessageConstants.PLAN_GROUP_NAME_EXITS;
                }
                RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                response.put(APIConstants.ERROR_TAG, errMsg);
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create planGroup" + LogConstants.LOG_BY_NAME + planGroupDTO.getPlanGroupName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_INFO + "Plangroup with same name already exist" + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }

        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create planGroup" + LogConstants.LOG_BY_NAME + planGroupDTO.getPlanGroupName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception e) {

            Integer responseCode = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create planGroup" + LogConstants.LOG_BY_NAME + planGroupDTO.getPlanGroupName() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + e.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            return apiResponse(responseCode, response);

        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, null);
    }

