            planGroupDTO.setPlanGroupId(id);
            // TODO: pass mvnoID manually 6/5/2025
            PlanGroup planGroupVo = planGroupService.updatePlanGroup(planGroupDTO, mvnoId);
            planGroupVo.setProductPlanGroupMappingList(planGroupDTO.getProductPlanGroupMappingList());
            planGroupService.sendCreateDataShared(planGroupVo, CommonConstants.OPERATION_UPDATE);
