    @PostMapping("/parentCustomers/list/{type}")
    public ResponseEntity<?> getParentCustomersListByPagination(@RequestBody PaginationRequestDTO requestDTO, HttpServletRequest req, @PathVariable String type,@RequestParam("mvnoId") Integer mvnoId) throws Exception {
        Page<Customers> pageRes = null;
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            CustomersService customerService = SpringContext.getBean(CustomersService.class);
            requestDTO = setDefaultPaginationValues(requestDTO);
            pageRes = customerService.getListByParentCustomerType(requestDTO.getPage(), requestDTO.getPageSize(), requestDTO.getSortBy(), requestDTO.getSortOrder(), requestDTO.getFilters(), type, requestDTO.getStatus(),mvnoId);
            if (null != pageRes && 0 < pageRes.getSize()) {
                response.put("parentCustomerList", pageRes.stream().map(data -> {
                    try {
                        return subscriberDetailsMapper.domainToDTO(data, new CycleAvoidingMappingContext());
                    } catch (NoSuchFieldException e) {
                        e.printStackTrace();
                    }
                    return null;
                }).collect(Collectors.toList()));
                response.put("parentCustomerList", pageRes.stream().filter(data -> data.getParentCustomers() == null).map(data -> {
                    try {
                        return subscriberDetailsMapper.domainToDTO(data, new CycleAvoidingMappingContext());
                    } catch (NoSuchFieldException e) {
                        e.printStackTrace();
                    }
                    return null;
                }).collect(Collectors.toList()));
            } else response.put("parentCustomerList", new ArrayList<>());
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch parent Customers List" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch parent Customers List" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch parent Customers List" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response, pageRes);
    }

