//    @PreAuthorize("validatePermission(\"" + MenuConstants.PrepaidCustomers.PREPAID_CUSTOMER_CHARGE_CREATE + "\",\"" + MenuConstants.PrepaidCustomerCAF.PREPAID_CAF_CUSTOMER_CHARGE_CREATE + "\",\"" + MenuConstants.PostpaidCustomerCAF.POSTPAID_CAF_CUSTOMER_CHARGE_CREATE + "\",\"" + MenuConstants.PostpaidCustomers.POSTPAID_CUSTOMER_CHARGE_CREATE + "\")")
    @PostMapping("/createCustChargeOverride")
    public ResponseEntity<?> createCustChargeOverride(@RequestBody CustChargeOverrideDTO custChargeOverrideDTO, HttpServletRequest req, @RequestHeader(value = "rf", defaultValue = "bss") String requestFrom, HttpServletRequest request) throws Exception {
        HashMap<String, Object> response = new HashMap<>();
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Create");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        Customers customer = customersRepository.findById(custChargeOverrideDTO.getCustid()).get();
        try {
            if(customer != null){
                if (getLoggedInUserPartnerId() != CommonConstants.DEFAULT_PARTNER_ID) {
                    if (requestFrom.equals("pw") && !getLoggedInUser().getLco() && customersService.isPartnerBalanceInsufficient(custChargeOverrideDTO)) {
                        RESP_CODE = HttpStatus.NOT_ACCEPTABLE.value();
                        response.put(APIConstants.ERROR_TAG, "Partner has Insufficient balance!");
                        log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_CREATED + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                        return apiResponse(RESP_CODE, response, null);
                    }
                }

                CustChargeService custChargeService = SpringContext.getBean(CustChargeService.class);
                response.put("custChargeOverride", custChargeService.createCustChargeOverride(custChargeOverrideDTO));
                RESP_CODE = APIConstants.SUCCESS;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                throw new CustomValidationException(HttpStatus.EXPECTATION_FAILED.value(), "customer not found", null);
            }
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            response.put(APIConstants.MESSAGE, ex.getStackTrace());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        }
        try {
            List<Integer> chargeIdList1 = new ArrayList<>();
            if (custChargeOverrideDTO.getCustChargeDetailsPojoList() != null && custChargeOverrideDTO.getCustChargeDetailsPojoList().size() > 0) {
                if (custChargeOverrideDTO.getCustChargeDetailsPojoList().get(0).getBillTo().equalsIgnoreCase(Constants.ORGANIZATION) && custChargeOverrideDTO.getCustChargeDetailsPojoList().get(0).getIsInvoiceToOrg()) {
                    for (CustChargeDetailsPojo custChargeDetailsPojo : custChargeOverrideDTO.getCustChargeDetailsPojoList()) {
                        CustomersPojo subscriber = customerMapper.domainToDTO(customer, new CycleAvoidingMappingContext());
                        CustChargeDetails details = customersService.saveDirectChargeDataForOrganizationCustomer(subscriber, customer.getCusttype(), custChargeDetailsPojo);
                        if (details != null) chargeIdList1.add(details.getId());
                    }
                }
                if (chargeIdList1 != null && !chargeIdList1.isEmpty()) {
                    Integer custId = 1;
                    if (!customer.getCusttype().equalsIgnoreCase("Prepaid")) custId = 2;
                    Runnable chargeRunnable1 = new ChargeThread(custId, chargeIdList1, customersService, 0L, custChargeOverrideDTO.getPaymentOwner(), custChargeOverrideDTO.getPaymentOwnerId());
                    Thread invoiceThread1 = new Thread(chargeRunnable1);
                    invoiceThread1.start();
                }
            }

        } catch (CustomValidationException ce) {
            ce.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.MESSAGE, ce.getMessage());
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            ex.printStackTrace();
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "create customer ChargeOverride" + LogConstants.LOG_BY_NAME + custChargeOverrideDTO.getPaymentOwner() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

