    @PreAuthorize("validatePermission(\"" + MenuConstants.PrepaidCustomers.PREPAID_CUSTOMER_SERVICE_MANAGEMENT + "\",\"" + MenuConstants.PrepaidCustomerCAF.PREPAID_CAF_CUSTOMER_SERVICE_MANAGEMENT + "\",\"" + MenuConstants.PostpaidCustomerCAF.POSTPAID_CAF_CUSTOMER_SERVICE_MANAGEMENT + "\",\"" + MenuConstants.PostpaidCustomers.POSTPAID_CUSTOMER_SERVICE_MANAGEMENT + "\")")
    @PostMapping("/shiftCustomerLocation/{custId}")
    public ResponseEntity<?> shiftCustomerLocation(@RequestBody ShiftLocationDTO shiftLocationDTO, @PathVariable Integer custId, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Update");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();

        try {

            CustomerAddressService customerAddressService = SpringContext.getBean(CustomerAddressService.class);
            CustomersService customersService = SpringContext.getBean(CustomersService.class);
//            Customers customers = customersService.get(custId);
            List<CustomerAddress> addresses = customerAddressRepository.findAllByCustomerId(custId);
            addresses.sort(Comparator.comparing(CustomerAddress::getId).reversed());
            String Address1 = addresses.get(0).getAddress1();
            CustomerAddress oldAddress = addresses.isEmpty() ? null : addresses.get(0);
            List<String> oldValues = customerAddressService.extractOldAddressValues(oldAddress);
            shiftLocationDTO = customerAddressService.shiftCustomerLocation(shiftLocationDTO, custId);
            // Extract new address only for audit
            CustomerAddressPojo newAddress = shiftLocationDTO.getAddressDetails();
            List<String> newValues = customerAddressService.extractNewAddressValues(newAddress);
            // Audit log
            String fieldName = getLoggedInUser().getFullName();
            String updateRemark = UpdateDiffFinder.generateListDiffRemark(oldValues, newValues,fieldName );
            auditLogService.addAuditEntry(
                    AclConstants.ACL_CLASS_CUSTOMER,
                    AclConstants.OPERATION_SHIFT_LOCATION,
                    req.getRemoteAddr(),
                    updateRemark,
                    custId.longValue(),
                    (oldAddress != null) ? oldAddress.getCustomer().getFullName() : null
            );
            response.put("shiftLocationDTO", shiftLocationDTO);
            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update shift Customer Location" + LogConstants.LOG_BY_NAME + customersRepository.findById(custId).get().getUsername() + " old address " + Address1 + "  to new address " + shiftLocationDTO.getAddressDetails() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {
            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update shift Customer Location" + LogConstants.LOG_BY_NAME + customersRepository.findById(custId).get().getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "update shift Customer Location " + LogConstants.LOG_BY_NAME + customersRepository.findById(custId).get().getUsername() + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }

        return apiResponse(RESP_CODE, response);
    }
