    public List<ChangeDiscountDTO> changeCustomerDiscount(List<ChangeDiscountDTO> requestDto, Integer custId) {
        List<ChangeDiscountDTO> response = new ArrayList<ChangeDiscountDTO>();
        List<CustPlanMappping> list = custPlanMappingRepository.getAllCustPlanMappingWithActiveAndFutuerBycustomerId(custId);
        list.stream().forEach(custPlan -> {
            Optional<ChangeDiscountDTO> changeDto = requestDto.stream().filter(dto -> dto.getId().equals(custPlan.getId())).findAny();
            if (changeDto.isPresent()) {
                custPlan.setDiscount(changeDto.get().getNewDiscount());
                //custPlan.setDiscount(changeDto.get().getOldDiscount());
            }
        });
        list = custPlanMappingRepository.saveAll(list);
        list.stream().forEach(custPlan -> {
            ChangeDiscountDTO changeDiscount = new ChangeDiscountDTO(custPlan.getId(), custId, custPlan.getPlanId(), custPlan.getDiscount(), 0d, custPlan.getStartDate(), custPlan.getEndDate());
            response.add(changeDiscount);
        });
        return response;
    }

