    @GetMapping("/newcustomeraddress/{custid}")
    public ResponseEntity<?> getNewCustomerAddress(@PathVariable Integer custid, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            CustomersService customerService = SpringContext.getBean(CustomersService.class);
            CustomerAddressService customerAddressService = SpringContext.getBean(CustomerAddressService.class);
            Customers customer = customersRepository.findById(custid).get();
            if (customer != null) {
                List<CustomerAddress> newcustomerAddressList = customerAddressService.findNewAddressByCustomer(custid);
                List<CustomerAddressPojo> customerAddressPojoList = new ArrayList<>();
                ShiftLocation shiftLocation = new ShiftLocation();
                shiftLocation = shiftLocationRepository.findLatestByCustomerId(customer.getId());
                if(!newcustomerAddressList.isEmpty()) {
                    for (CustomerAddress newcustomerAddress : newcustomerAddressList) {
                        if(shiftLocation != null) {
                            newcustomerAddress.setRequestedDate(shiftLocation.getRequestedDate());
                            newcustomerAddress.setRequestedByName(shiftLocation.getRequestedByName());

                        }
                        CustomerAddressPojo customerAddressPojo = customerAddressService.convertCustomerAddressModelToCustomerAddressPojo(newcustomerAddress);
                        customerAddressPojoList.add(customerAddressPojo);
                    }
                    response.put("newcustomerAddress", customerAddressPojoList);
                    RESP_CODE = APIConstants.SUCCESS;
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch shift location" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                }
                else{
                    RESP_CODE = APIConstants.NO_CONTENT_FOUND;
                    response.put("message","No record Fouund While Fetch New Customer Address.");
                    log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch shift location" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                }
            } else {
                RESP_CODE = APIConstants.FAIL;
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch shift location" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
                throw new CustomValidationException(APIConstants.FAIL, "Customer is not found", null);
            }
        } catch (CustomValidationException ce) {
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch shift location" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch shift location" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

