    @PostMapping("/socialLogin")
    public GenericDataDTO sociallogin(@Valid @RequestBody Customers pojo, HttpServletRequest req) throws Exception {
        Integer RESP_CODE = APIConstants.FAIL;
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        try {
            TraceContext traceContext = tracer.currentSpan().context();
            MDC.put("type", "Fetch");
            MDC.put("userName", getLoggedInUser().getUsername());
            MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
            MDC.put("spanId", traceContext.spanIdString());
            CustomersService customersService = SpringContext.getBean(CustomersService.class);
            Boolean flag = customersService.validateCustomerRegistration(pojo);
            if (flag) {
                Customers customers = customersService.registercustomer(pojo);
                if (customers != null) {
                    genericDataDTO.setResponseCode(APIConstants.SUCCESS);
                    genericDataDTO.setResponseMessage("Customer Registered Successfully");
                    genericDataDTO.setData(customers);
                } else {
                    genericDataDTO.setResponseCode(APIConstants.FAIL);
                    genericDataDTO.setResponseMessage("Unable to register");
                }
            } else {
                Customers customers = customersService.otpVAlidation(pojo);
                if (customers != null) {
                    genericDataDTO.setResponseCode(APIConstants.SUCCESS);
                    genericDataDTO.setResponseMessage("Customer Registered Successfully");
                    genericDataDTO.setData(customers);
                }
                genericDataDTO.setResponseCode(APIConstants.FAIL);
                genericDataDTO.setResponseMessage("Unable to verify the user");
            }

            RESP_CODE = APIConstants.SUCCESS;
            log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch upload File" + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (CustomValidationException ce) {

        } catch (Exception e) {
            e.getStackTrace();

        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return genericDataDTO;
    }

