    @PreAuthorize("validatePermission(\"" + MenuConstants.PrepaidCustomers.PREPAID_CUSTOMERS + "\",\"" + MenuConstants.PrepaidCustomerCAF.PREPAID_CAF_CUSTOMERS + "\",\"" + MenuConstants.PostpaidCustomers.POSTPAID_CUSTOMERS + "\"" + ",\"" + MenuConstants.PostpaidCustomerCAF.POSTPAID_CAF_CUSTOMERS + "\")")
    @GetMapping("/customers/details/{id}")
    public ResponseEntity<?> getCustomersDetailsById(@PathVariable Integer id, HttpServletRequest req) throws Exception {
        TraceContext traceContext = tracer.currentSpan().context();
        MDC.put("type", "Fetch");
        MDC.put("userName", getLoggedInUser().getUsername());
        MDC.put(LogConstants.TRACE_ID, req.getHeader(LogConstants.TRACE_ID));
        MDC.put("spanId", traceContext.spanIdString());
        Integer RESP_CODE = APIConstants.FAIL;
        HashMap<String, Object> response = new HashMap<>();
        try {
            CustomersService customersService = SpringContext.getBean(CustomersService.class);
            PostpaidPlanService planService = SpringContext.getBean(PostpaidPlanService.class);

            CustomersDetailsPojo customersDetailsPojo = customersService.getCustomerDetailsById(id);

            if (customersDetailsPojo == null) {
                RESP_CODE = APIConstants.NOT_FOUND;
                response.put("message", "Customer is not found by given id : " + id);
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, req.getRemoteAddr(), null, id.longValue(), "");
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers details by id " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_NOT_FOUND + LogConstants.LOG_INFO + LogConstants.LOG_NO_RECORD_FOUND + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            } else {
                if (customersDetailsPojo.getPlanMappingList() != null && customersDetailsPojo.getPlanMappingList().size() > 0) {
                    if (customersDetailsPojo.getPlanMappingList().stream().filter(custPlanMappping -> custPlanMappping.getInvoiceType().equals(CommonConstants.INVOICE_TYPE_INDEPENDENT)).count() > 0) {
                        customersDetailsPojo.setInvoiceType(CommonConstants.INVOICE_TYPE_INDEPENDENT);
                    } else {
                        customersDetailsPojo.setInvoiceType(CommonConstants.INVOICE_TYPE_GROUP);
                    }
                } else {
                    customersDetailsPojo.setInvoiceType(CommonConstants.INVOICE_TYPE_GROUP);
                }
                long childCustCount = customersService.getChildCustomerCount(customersDetailsPojo.getId(), CommonConstants.INVOICE_TYPE_GROUP);
                customersDetailsPojo.setHasChildCust(childCustCount > 0);
                response.put("customers", customersDetailsPojo);
                RESP_CODE = APIConstants.SUCCESS;
                auditLogService.addAuditEntry(AclConstants.ACL_CLASS_CUSTOMER, AclConstants.OPERATION_CUSTOMER_VIEW, req.getRemoteAddr(), null, customersDetailsPojo.getId().longValue(), customersDetailsPojo.getCustname());
                log.info(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers details by id " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_SUCCESS + LogConstants.LOG_STATUS_CODE + RESP_CODE);
            }

        } catch (CustomValidationException ce) {

            //		ApplicationLogger.logger.error(MODULE + ce.getStackTrace(), ce);
            ce.printStackTrace();
            RESP_CODE = ce.getErrCode();
            response.put(APIConstants.ERROR_TAG, ce.getMessage());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers details by id " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ce.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } catch (Exception ex) {
            //		ApplicationLogger.logger.error(MODULE + ex.getStackTrace(), ex);
            ex.printStackTrace();
            RESP_CODE = HttpStatus.EXPECTATION_FAILED.value();
            response.put(APIConstants.ERROR_TAG, HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            log.error(LogConstants.REQUEST_FROM + req.getHeader("requestFrom") + LogConstants.REQUEST_FOR + "fetch customers details by id " + id + LogConstants.REQUEST_BY + getLoggedInUser().getUsername() + LogConstants.LOG_STATUS + LogConstants.LOG_FAILED + LogConstants.LOG_ERROR + ex.getMessage() + LogConstants.LOG_STATUS_CODE + RESP_CODE);
        } finally {
            MDC.remove("type");
            MDC.remove("userName");
            MDC.remove("traceId");
            MDC.remove("spanId");
        }
        return apiResponse(RESP_CODE, response);
    }

