    @GetMapping("/BuildingAndSubareaNames/{id}")
    public GenericDataDTO getEntityById(@PathVariable Integer id) {
        GenericDataDTO genericDataDTO = new GenericDataDTO();
        try {
            // Fetch customer details from service
            GenericDataDTO customerDetails = customersService.getCustomerDetails(id);

            if (customerDetails != null && customerDetails.getData() != null) {
                genericDataDTO.setResponseCode(HttpStatus.OK.value());
                genericDataDTO.setResponseMessage("Success");
                genericDataDTO.setData(customerDetails.getData());
            } else {
                // No customer details found or no data returned
                genericDataDTO.setResponseCode(HttpStatus.NOT_FOUND.value());
                genericDataDTO.setResponseMessage("Customer Not Found or No Data Available");
                genericDataDTO.setData(Collections.emptyList());  // Empty list for clarity
            }
        } catch (Exception e) {
            // In case of any error (e.g., database connection failure, etc.)
            genericDataDTO.setResponseCode(HttpStatus.INTERNAL_SERVER_ERROR.value());
            genericDataDTO.setResponseMessage("Error occurred while fetching customer details: " + e.getMessage());
            genericDataDTO.setDataList(Collections.emptyList());
            genericDataDTO.setTotalRecords(0);
        }
        return genericDataDTO;
    }

