    @GetMapping("/customers/{id}/currency")
    public ResponseEntity<?> getCustomerCurrencyById(@PathVariable Integer id) {
        Map<String, Object> response = new HashMap<>();
        int responseCode = APIConstants.FAIL;
        try {
            Optional<String> currencyOpt = customersRepository.findCurrencyByCustomerId(id);
            if (!currencyOpt.isPresent()) {
                responseCode = APIConstants.NOT_FOUND;
                response.put("message", "Currency not found for customer id: " + id);
                response.put("responseCode", responseCode);
                response.put("timestamp", LocalDateTime.now().toString());
                return new ResponseEntity<>(response, HttpStatus.NOT_FOUND);
            }
            String currency = currencyOpt.get();
            responseCode = APIConstants.SUCCESS;
            response.put("currency", currency);
            response.put("responseCode", responseCode);
            response.put("timestamp", LocalDateTime.now().toString());
            return new ResponseEntity<>(response, HttpStatus.OK);
        } catch (Exception ex) {
            responseCode = HttpStatus.EXPECTATION_FAILED.value();
            response.put("error", HttpStatus.EXPECTATION_FAILED.getReasonPhrase());
            response.put("responseCode", responseCode);
            response.put("timestamp", LocalDateTime.now().toString());
            return new ResponseEntity<>(response, HttpStatus.EXPECTATION_FAILED);
        }
    }

